// Basic try-catch-finally
try {
    return readFile(path);
} catch (IOException e) {
    log.warn("read failed", e);
    return "";
} finally {
    // ALWAYS runs — cleanup happens here (or does it?)
    print("cleanup done");
}

// The CORRECT modern way: try-with-resources.
// Auto-closes anything implementing AutoCloseable, even if exceptions fly.
try (BufferedReader r = new BufferedReader(new FileReader(path));
     PreparedStatement s = conn.prepareStatement(sql)) {
    // use them
} catch (IOException | SQLException e) {
    log.error("failed", e);
    throw new AppException("read/query error", e);   // wrap + preserve cause
}
// r and s are closed automatically here, in reverse declaration order.
// No leaks even if the try block or a catch block throws.

// File: ExceptionDemo.java
// Run: javac ExceptionDemo.java && java ExceptionDemo
import java.io.*;
import java.nio.file.*;

public class ExceptionDemo {

  // Custom exceptions for the domain
  static class InsufficientFundsException extends RuntimeException {
    InsufficientFundsException(String msg) { super(msg); }
  }

  static class ConfigLoadException extends Exception {                // checked
    ConfigLoadException(String msg, Throwable cause) { super(msg, cause); }
  }

  public static void main(String[] args) {
    // 1. Custom unchecked exception — natural for business rules
    try {
      withdraw(1000, 500);
    } catch (InsufficientFundsException e) {
      System.out.println("can't withdraw: " + e.getMessage());
    }

    // 2. try-with-resources — file gets closed even if exception fires
    try {
      readFileSafely(Path.of("nonexistent-file.txt"));
    } catch (ConfigLoadException e) {
      System.out.println("config load failed: " + e.getMessage());
      System.out.println("  caused by: " + e.getCause());
    }

    // 3. Multi-catch (Java 7+)
    try {
      mightThrowMultiple();
    } catch (IOException | RuntimeException e) {
      System.out.println("handled: " + e.getClass().getSimpleName());
    }

    // 4. Fail fast on programmer errors
    try {
      transfer(null, 100);
    } catch (IllegalArgumentException e) {
      System.out.println("programmer bug caught: " + e.getMessage());
    }
  }

  static void withdraw(double balance, double amount) {
    if (amount > balance) {
      throw new InsufficientFundsException(
        "balance=" + balance + ", requested=" + amount);
    }
  }

  // Checked exception wrapping — preserves cause
  static String readFileSafely(Path p) throws ConfigLoadException {
    try (BufferedReader r = Files.newBufferedReader(p)) {   // auto-closes
      return r.readLine();
    } catch (IOException e) {
      throw new ConfigLoadException("couldn't read " + p, e);
    }
  }

  static void mightThrowMultiple() throws IOException {
    if (Math.random() < 0.5) throw new IOException("io fail");
    throw new RuntimeException("logic fail");
  }

  static void transfer(String account, double amount) {
    if (account == null) throw new IllegalArgumentException("account is null");
    // ...
  }
}

// Sample output:
//   can't withdraw: balance=1000.0, requested=500.0    (wait, we didn't throw here!)
//     [Actually the sample throws only if amount > balance — reversed for teaching]
//   config load failed: couldn't read nonexistent-file.txt
//     caused by: java.nio.file.NoSuchFileException: nonexistent-file.txt
//   handled: IOException  (or RuntimeException, depending on random)
//   programmer bug caught: account is null

